import { Image, Input } from 'antd'
import dayjs from 'dayjs'
import type { TStoryChartItem } from '@/apis'

interface StoryReportProps {
  title: string
  author?: string
  description?: string
  createTime?: number
  charts: TStoryChartItem[]
  editable?: boolean
  onEdit?: (idx: number, content: string) => void
}

const fallbackImage="data:image/png;base64,"

export default function StoryReport({
  title,
  author,
  description,
  createTime,
  charts,
  editable,
  onEdit,
}: StoryReportProps) {
  return (
    <div className="mx-auto w-full bg-white">
      <div className="h-1.5 w-full bg-blue-500" />
      <div className="px-5 py-4 text-center">
        <h2 className="font-bold text-gray-900 sm:text-lg">
          {title || '未命名报告'}
        </h2>
        <p className="mt-1 text-sm text-gray-500">
          {author ? `${author} ` : ''}
          {createTime ? dayjs(createTime).format('YYYY.MM.DD') : ''}
        </p>
      </div>

      <div className="space-y-5 px-5 pb-6">
        {description ? (
          <div className="py-3 text-sm text-gray-900">{description}</div>
        ) : null}
        {charts.length === 0 ? (
          <div className="py-10 text-center text-sm text-gray-400">
            尚未添加图表
          </div>
        ) : (
          charts.map((chart, idx) => (
            <div
              key={`${chart.chartId}`}
              className="print:break-inside-avoid"
            >
              <div className="flex items-center justify-center overflow-hidden rounded-sm border border-gray-100 bg-gray-50">
                <Image
                  src={chart.thumbnailUrl || ''}
                  alt={chart.chartName || ''}
                  width={'100%'}
                  className="max-h-128 object-contain"
                  fallback={fallbackImage}
                />
              </div>

              {editable && onEdit ? (
                <p className="mt-3 rounded-sm bg-blue-50/60 p-3 text-xs leading-relaxed whitespace-pre-wrap text-gray-700">
                  <Input.TextArea
                    placeholder="请输入该图表的解读内容..."
                    autoSize={{ minRows: 3, maxRows: 8 }}
                    value={chart.description || ''}
                    onChange={(e) => onEdit(idx, e.target.value)}
                  />
                </p>
              ) : chart.description ? (
                <p className="mt-3 rounded-sm bg-blue-50/60 p-3 text-xs leading-relaxed whitespace-pre-wrap text-gray-700">
                  {chart.description}
                </p>
              ) : null}
            </div>
          ))
        )}
      </div>

      <div className="border-t border-gray-100 px-5 py-3 text-center text-[11px] leading-relaxed text-gray-400">
        声明：当前数据报告系用户自行创建，平台未对报告所涉数据的真实性、准确性、完整性进行校验，因报告内容引发的相关责任由用户自行承担。
      </div>
    </div>
  )
}
